        ON DUPLICATE KEY UPDATE 
            keyword = VALUES(keyword),
            title = VALUES(title),
            meta_desc = VALUES(meta_desc),
            h1_title = VALUES(h1_title),
            content = VALUES(content),
            faq_data = VALUES(faq_data),
            schema_type = VALUES(schema_type),
            status = 'published'
    ");
    $stmt->execute([
        'slug' => $slug_view,
