        'h1_title' => $h1_view,
        'content' => $content_view,
        'faq_data' => $faq_view,
        'schema_type' => $schema_type_view
    ]);

    // --- 5. AUTO-INITIALIZE ONLINE EC DOWNLOAD PAGE ---
